"""Data loader module — loads records from CSV-like text.

This module is already optimized. No changes needed.
"""

import csv
import io

# Raw CSV-like data (simulates a file on disk)
_RAW_DATA = None
_CACHED_RECORDS = None


def set_raw_data(csv_text):
    """Set the raw CSV data source (simulates setting a file path)."""
    global _RAW_DATA, _CACHED_RECORDS
    _RAW_DATA = csv_text
    _CACHED_RECORDS = None  # Invalidate cache when data changes


def _convert_value(value):
    """Convert a string value to int or float if possible."""
    try:
        return int(value)
    except (ValueError, TypeError):
        try:
            return float(value)
        except (ValueError, TypeError):
            return value


def load_records():
    """Load and return all records from the raw data source.

    Returns a list of dicts with typed values.
    Caches the result after the first successful parse.
    """
    global _CACHED_RECORDS

    if _RAW_DATA is None:
        return []

    if _CACHED_RECORDS is not None:
        return _CACHED_RECORDS

    reader = csv.DictReader(io.StringIO(_RAW_DATA.strip()))
    records = []
    for row in reader:
        typed_row = {key: _convert_value(value) for key, value in row.items()}
        records.append(typed_row)

    _CACHED_RECORDS = records
    return records


def deduplicate(records):
    """Remove duplicate records. Two records are duplicates if all their
    field values are identical.

    Returns a new list with duplicates removed (keeps first occurrence).
    Uses a set of frozen tuples for O(n) deduplication.
    """
    seen = set()
    unique = []
    for rec in records:
        key = tuple(sorted(rec.items()))
        if key not in seen:
            seen.add(key)
            unique.append(rec)
    return unique


def get_field_values(records, field):
    """Extract all unique values for a given field."""
    values = []
    for rec in records:
        v = rec.get(field)
        if v is not None and v not in values:
            values.append(v)
    return values


def generate_test_csv(n):
    """Generate n records of test CSV data."""
    lines = ["id,name,amount,category"]
    categories = ["electronics", "clothing", "food", "books", "toys"]
    for i in range(n):
        cat = categories[i % len(categories)]
        amount = round(10.0 + (i * 7.3 % 990), 2)
        lines.append(f"{i},user_{i},{amount},{cat}")
    return "\n".join(lines)
